examples.bad:
func transfer(amount: Decimal, to: Account) async throws {
  try await api.transfer(amount: amount, destination: to.id)
}

examples.good:
func transfer(amount: Decimal, to: Account) async throws {
  AuditLogger.log(.transferInitiated, amount: amount, destination: to.id)
  do {
    try await api.transfer(amount: amount, destination: to.id)
    AuditLogger.log(.transferCompleted, amount: amount, destination: to.id)
  } catch {
    AuditLogger.log(.transferFailed, amount: amount, error: error)
    throw error
  }
}

examples.bad:
func initiateTransfer(amount: Decimal) async throws {
  try await api.transfer(amount: amount) // ❌ No limit check
}

examples.good:
func initiateTransfer(amount: Decimal) async throws {
  guard amount <= LimitPolicy.singleTransactionMax else {
    throw TransferError.exceedsLimit
  }
  guard try await dailyLimitService.hasCapacity(for: amount) else {
    throw TransferError.dailyLimitExceeded
  }
  try await api.transfer(amount: amount)
}

override func viewWillAppear(_ animated: Bool) {
  super.viewWillAppear(animated)
  NotificationCenter.default.addObserver(self, selector: #selector(handleRecording),
    name: UIScreen.capturedDidChangeNotification, object: nil)
}
@objc func handleRecording() {
  sensitiveView.isHidden = UIScreen.main.isCaptured
}

class SessionManager {
  private var timer: Timer?
  func resetTimer() {
    timer?.invalidate()
    timer = Timer.scheduledTimer(withTimeInterval: 300, repeats: false) { _ in
      self.logout()
    }
  }
}
